var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"끔찍하군. 이 많은 잡동사니들 중에 물수건이라곤 달랑 이거 한 통이 전부라니.","JPN":"ひどいな。こんな多くのがらくたの中に、タオルがたった一枚しかないなんて。","ENG":"How horrendous. There's all this junk around, but this is the only usable packet of moist towelettes.","TWN":"真恐怖，這麼多雜物中竟然只有這一盒濕毛巾。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무리 단기작전이라도 보급품이 이렇게 적으면 문제가 생길 텐데. 아낄 걸 아껴야지.","JPN":"いくら短期作戦とはいえ、補給品がここまで少ないと後にトラブルが生じるはずだが。節約すべき物とそうではない物があるだろうに。","ENG":"I know this was meant to be a brief operation, but there are going to be issues with such few supplies. He's cut way too many corners.","TWN":"即使是短期作戰，補給品這麼少肯定會出問題的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나머지는 전부 윌버 녀석이 쓰는 장비들인가? 저런 거 본 적 있어?","JPN":"残りはウィルバーの奴が使う装備か？　なあ、見たことあるか？","ENG":"Is the rest of the stuff Wilbur's gear? Have you seen anything like that before?","TWN":"剩下的都是韋爾伯那傢伙的裝備嗎？你看過這些東西嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 왜 아무 말도 없어?","JPN":"ホライズン、なぜ無口なんだ？","ENG":"Why aren't you saying anything, Horizon?","TWN":"地平線，你怎麼一句話也不說？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당신이 그 한심한 제안을 받아들인 탓에 제 언어 회로에 문제가 발생했습니다.","JPN":"あなたが彼のくだらない提案を受け入れたせいで、私の言語回路に問題が発生しました。","ENG":"Ever since you accepted that ridiculous offer, my language processing algorithm has had trouble computing.","TWN":"就因為聽了你那乏味的提議，我的語言迴路出現了問題。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"입을 열면 리타를 지칭하는 아주 부적절한 단어들이 출력될 것 같아서 참고 있죠.","JPN":"口を開けるとリタを指す非常に不適切な単語が出力されそうなので、我慢しています。","ENG":"I've opted for silence as any mention of your name may be appended with highly unprofessional language.","TWN":"我怕一開口會忍不住對你用一些不適當的形容詞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럼 계속 입 다물고 있어. 대표면 말도 품위 있게 해야지.","JPN":"そうか。ならそのまま黙っててくれ。代表なら品のある言葉を使わないとな。","ENG":"Then keep your mouth shut. I can't have my boss resorting to foul language.","TWN":"那你就繼續閉嘴吧。身為BOSS，要注意言辭。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"시끄럽습니다, 휴먼.","JPN":"うるさいですね、ヒューマン。","ENG":"Oh, shut up, human.","TWN":"吵死了，人類。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대체 왜 이번 일을 하기로 한 겁니까?","JPN":"どうして今回の探査に参加したのですか？","ENG":"Why on earth did you agree to do this anyway?","TWN":"到底為什麼要這麼做？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"윌버를 찾다가 평의회 놈을 만났어. 예전 생각이 나더군.","JPN":"ウィルバーを探していた時、評議会の奴に会った。昔のことを思い出してな。","ENG":"I ran into a Council member while looking for Wilbur. It reminded me of the olden days.","TWN":"在找韋爾伯的時候遇到了評議會的傢伙，想起了之前的事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"혹시 당신의 생물학적 부친과 관련된 일입니까?","JPN":"もしかして、あなたの生物学上の父親のことですか？","ENG":"Does this have anything to do with your biological father?","TWN":"難道是跟你父親有關？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그 일이라면 당신은 자신의 의무를 충분히 다했습니다.","JPN":"そのことでしたら、あなたは自身の義務を十分に果たしました。","ENG":"You've already done your due diligence when it comes to that matter.","TWN":"如果是的話，你已經充分盡到了義務。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아버지의 뜻을 지키기 위해 거액을 지불했으니까요.","JPN":"父の意志を守るために巨額を支払いましたから。","ENG":"You've paid a heavy price to ensure your father's legacy, after all.","TWN":"為了守護你父親的意願，支付了鉅款不是嗎。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아니면, 저 불량 채무자가 <color=#ffd34c>아르세니코 패밀리</color>와 무슨 관계가 있는 겁니까?","JPN":"それとも、あの悪質な債務者が<color=#ffd34c>アルセニコファミリー</color>と何か関係があるのですか？","ENG":"Or does that ingrate borrower have anything to do with the <color=#ffd34c>Arsenicos</color>?","TWN":"不然的話，難道那個不良債務人跟<color=#ffd34c>阿塞妮克家族</color>有什麼關係嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니, 그런 게 아냐.","JPN":"いや、そうじゃない。","ENG":"No, it's nothing like that.","TWN":"不、不是那樣的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그저...... 누구한테나 마지막 기회가 필요하다는 생각이 들었을 뿐이지.","JPN":"ただ……誰にでも最後のチャンスは必要だと思っただけだ。","ENG":"It's just that... I realized everyone deserves a last chance.","TWN":"只是……覺得不管是誰都需要最後一次的機會罷了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 생각이 그렇다면 말리진 않겠습니다.","JPN":"リタがそう考えているなら止めはしません。","ENG":"If you really think so, I won't stop you.","TWN":"既已如此，我不會阻攔。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"하지만 모든 탄소생명체가 리타처럼 하는 것은 아닙니다.","JPN":"しかし、すべての炭素生命体がリタのように行動するわけではありません。","ENG":"But not all carbon-based lifeforms think like you.","TWN":"但並不是所有的碳結構生命體都像麗塔一樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"오랜 시간 금융업에 종사해 온 저의 데이터베이스가 그 증거죠.","JPN":"長きにわたり金融業に携わってきた私のデータベースがその証拠です。","ENG":"The years of financial databases I've compiled is proof.","TWN":"長期從事金融業的我所擁有的資料庫就是證據。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 네 말마따나 괜한 호의였을지도 모르지.","JPN":"そうだな。お前の言うとおり余計なお世話だったかもしれない。","ENG":"Yeah, I know. Maybe he doesn't deserve this like you said.","TWN":"嗯，也有可能像你說的一樣，是我好心氾濫。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어쨌거나 여기 온 이상 결판이 날 거야.","JPN":"まあここまで来た以上、ケリは付けられるだろう。","ENG":"In any case, we'll find out soon enough now that we're here.","TWN":"不管怎樣，既來之則安之吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무튼, 설명은 이거면 됐겠지?","JPN":"とりあえず説明はこれでいいな？","ENG":"Anyway, does that clear things up for you?","TWN":"好了，說明夠充分了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 물수건 가지고 가서 네가 꼬맹이 이마에 얹어 줘.","JPN":"このタオルを持ってガキの額にのっけてやれ。","ENG":"Just take this wet towel and put it on the kid's forehead.","TWN":"你把這個濕毛巾敷在小鬼的額頭上。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 녀석, 아까부터 다이브 멀미가 심한 것 같으니까.","JPN":"あいつ、さっきからダイブ酔いでしんどそうだったから。","ENG":"She seems to be struggling with the Dive sickness.","TWN":"那傢伙，好像從剛剛躍入開始後出現的眩暈症狀有些嚴重。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타는 이상합니다. 그렇게 대시가 걱정되면 자기 손으로 해 주면 되지 않습니까.","JPN":"リタは変です。そんなにダッシュのことが心配なら、自分で直接面倒をみてあげればいいのでは。","ENG":"I find you most puzzling sometimes, Rita. If you're so worried about Dash, why don't you tend to her yourself?","TWN":"麗塔你太奇怪了。既然你這麼擔心黛西，那就親自照顧她啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나 같은 거랑 친해지면 걔 평생이 고달파져. 넌 기계라 그런 건 잘 모르겠지만.","JPN":"私みたいな奴と仲良くなってもあいつの人生に悪影響を及ぼすだけさ。お前は機械だからわからないだろうが。","ENG":"Getting close to the likes of me will do the kid no good. I guess you won't get it since you're just a machine.","TWN":"如果她跟我這樣的人走的太近，會害了她一輩子的。你是機器，不會瞭解的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"감정이란 것은 직접 표현하지 않으면 상대가 알 수 없습니다.","JPN":"感情というものは直接表現しないと相手に伝わりません。","ENG":"Unless you express yourself, the other person will never know how you feel about them.","TWN":"既然關心，就要直接表現出來，不然對方是不會知道的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 꼬맹이한테 점수 따고 싶은 게 아냐. 그냥 다치지 않았으면 하는 거지.","JPN":"私は別にガキから好かれたいわけじゃない。ただ、怪我をしないでほしいだけ。","ENG":"I'm not out to win brownie points with the kid. I just don't want her to get hurt.","TWN":"我不是為了得到這小鬼的好感。只是單純不想讓她受傷害。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러니까 잔소리 그만하고......","JPN":"だから小言はその辺にしといて……","ENG":"So quit your nagging and—","TWN":"所以，你別囉嗦了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타, 수송선의 추진부가 피격 당했습니다.","JPN":"リタ、輸送船の推進機が攻撃を受けています。","ENG":"Rita, the ship's thrusters have been damaged.","TWN":"麗塔，運輸船的推進器遭到了破壞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"다수의 침식파 반응이 감지됩니다. 대응이 필요합니다.","JPN":"複数の侵食波反応を感知しました。直ちに対応が必要です。","ENG":"I've detected multiple Corruption Ray signatures. We must respond.","TWN":"檢測到很多侵蝕波反應。需要採取行動。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식파라고? 어째서 레이더가 포착하지 못한 거지?","JPN":"侵食波？　なぜレーダーに捕捉されなかったんだ？","ENG":"Corruption Rays? How come the radar didn't pick up on it?","TWN":"侵蝕波？雷達怎麼沒有捕捉到？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그야 이건 저심도 운용을 상정하고 건조됐던 구식 함선이기 때문이죠.","JPN":"それは、これが低深度運用を想定して建造された旧式の艦船だからです。","ENG":"That's because this ship was built for shallower Dives. Not to mention its age.","TWN":"因為這是以低深度為準建造的老式艦船。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이 정도 심도에서는 탐지장비가 무용지물이 될 겁니다.","JPN":"この程度の深度では探知装備が無用の長物になるでしょう。","ENG":"Its sensors are likely useless at this depth.","TWN":"在這種深度中，探測設備都是擺設，沒什麼用處。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"빌어먹을...... 하긴 윌버 놈이 멀쩡한 배를 제값 주고 빌렸을 리가 없지.","JPN":"くそっ……まあウィルバーがまともな船をまともな値段で借りたはずがないか。","ENG":"Dammit... Then again, of course Wilbur wouldn't pay for a proper ship.","TWN":"可惡……也是，韋爾伯那傢伙不可能租了什麼好船。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"안 나가 볼 겁니까?","JPN":"行かなくてもいいのですか？","ENG":"Aren't you going to go out there?","TWN":"不出去看看嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안 나가. 카트리지 안에서 담배나 하나 꺼내 줘.","JPN":"行かない。カートリッジの中からタバコを1本出してくれ。","ENG":"Nope. Just hand me a cig from the cartridge.","TWN":"不出去，給我從彈藥筒裡拿一支煙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"한 번만 다시 생각해 보십시오.","JPN":"もう一度考え直してみてはどうですか。","ENG":"I urge you to reconsider.","TWN":"再考慮一下吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"우리는 이터니움을 챙기러 온 거야. 침식체든 뭐든 자기네들이 알아서 하라고 해.","JPN":"私たちはエタニウムをいただきに来たんだ。侵食体だのなんだの、私たちには関係ない。","ENG":"We're only here to collect Eternium. They can figure out the rest, whether its C.O.s or whatever.","TWN":"我們是來找永恆之金的。侵蝕體之類的，讓他們自己看著辦就好了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"마지막입니다. 다시 생각해 보십시오, 리타.","JPN":"最後の警告です。考え直してください、リタ。","ENG":"I must urge you once last time. Please reconsider, Rita.","TWN":"最後一次，再考慮一下吧，麗塔。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜? CPU에 과전압이 흐른다더니 갑자기 인류애에 눈뜨기라도 했나?","JPN":"どうしたんだ？　CPUに過電圧がかかって、急に人類愛にでも目覚めたのか？","ENG":"Why? Has all that short-circuiting fried your chips into caring about humans all of a sudden?","TWN":"怎麼了？難不成你的CPU電壓過高，產生出什麼人類的感情了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대시에게 준 통신기의 신호가 갑판에서 감지되기 때문입니다.","JPN":"ダッシュに渡した通信機の信号が、甲板から感知されたからです。","ENG":"It's because I can detect the signal from Dash's communicator on the deck.","TWN":"因為剛在甲板上檢測到了給黛西的通訊器信號。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......이 망할 꼬맹이가 진짜.","JPN":"……あの馬鹿ガキ！","ENG":"That good-for-nothing kid!","TWN":"……這該死的小鬼，真是的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};